///   IDisposable is also implemented here for non-async disposal contexts.
/// </summary>
public sealed class BackgroundProcessor : IAsyncDisposable, IDisposable
{
    private readonly CancellationTokenSource _cts = new();
    private readonly Channel<WorkItem> _channel = Channel.CreateBounded<WorkItem>(
        new BoundedChannelOptions(capacity: 100)
        {
            FullMode = BoundedChannelFullMode.Wait
        });
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoopAsync(_cts.Token));
    }

