    /// Enqueue work. This replaces whatever was feeding GetNextItem() before.
    /// </summary>
    public async ValueTask EnqueueAsync(WorkItem item, CancellationToken ct = default)
    {
        await _channel.Writer.WriteAsync(item, ct);
    }

    private async Task ProcessLoopAsync(CancellationToken ct)
    {
        try
        {
            // ReadAllAsync yields items until the channel is completed AND empty,
            // or the CancellationToken fires.
            await foreach (var item in _channel.Reader.ReadAllAsync(ct))
